double convexHullPerimeter(std::vector<Point> const& points) {
    if (points.size() < 3) {
        // Handle edge cases: less than 3 points cannot form a polygon
        return 0.0;
    }

    // Find the point with the lowest y-coordinate, and use it as the starting point
    Point start = *std::min_element(points.begin(), points.end(), [](const Point &p1, const Point &p2) {
        return p1.y < p2.y || (p1.y == p2.y && p1.x > p2.x);
    });

    // Sort the remaining points in clockwise order around the starting point
    std::sort(points.begin(), points.end(), [&](const Point &p1, const Point &p2) {
        double crossProduct = (p2.x - start.x) * (p2.y + start.y) - (p1.x - start.x) * (p1.y + start.y);
        return crossProduct > 0;
    });

    // Initialize the convex hull with the first three points
    std::vector<Point> hull = {points[0], points[1]};
    for (size_t i = 2; i < points.size(); ++i) {
        while (hull.size() >= 2 && comparePoints(hull[hull.size()-2], hull.back(), points[i])) {
            hull.pop_back();
        }
        hull.push_back(points[i]);
    }

    // Compute the perimeter of the convex hull in parallel
    double totalPerimeter = 0.0;
    #pragma omp parallel for reduction(+ : totalPerimeter)
    for (size_t i = 0; i < hull.size(); ++i) {
        size_t j = (i + 1) % hull.size();
        totalPerimeter += distance(hull[i], hull[j]);
    }

    return totalPerimeter;
}
